import os
from Crypto.Cipher import AES
from Crypto.Util.Padding import pad, unpad

# Load encryption key from app configuration
ENCRYPTION_KEY = os.getenv('CREDIT_CARD_ENCRYPTION_KEY')

def encrypt_credit_card_number(credit_card_number):
    key = bytes.fromhex(ENCRYPTION_KEY)
    iv = os.urandom(AES.block_size)
    cipher = AES.new(key, AES.MODE_CBC, iv)
    encrypted_data = cipher.encrypt(pad(credit_card_number.encode('utf-8'), AES.block_size))
    return iv.hex() + ':' + encrypted_data.hex()

def decrypt_credit_card_number(encrypted_data):
    key = bytes.fromhex(ENCRYPTION_KEY)
    iv_hex, encrypted_data_hex = encrypted_data.split(':')
    iv = bytes.fromhex(iv_hex)
    cipher = AES.new(key, AES.MODE_CBC, iv)
    decrypted_data = unpad(cipher.decrypt(bytes.fromhex(encrypted_data_hex)), AES.block_size)
    return decrypted_data.decode('utf-8')

# Example usage
original_number = "1234567890123456"
encrypted_number = encrypt_credit_card_number(original_number)
decrypted_number = decrypt_credit_card_number(encrypted_number)

print("Original:", original_number)
